import{_ as t,c as r,G as s,b as o}from"./chunks/framework.DvhYz0iE.js";const n=JSON.parse('{"title":"计算机三级嵌入式背题","description":"计算机三级嵌入式背题.","frontmatter":{"title":"计算机三级嵌入式背题","tags":["笔记"],"categories":["笔记"],"date":"2026-03-25T00:00:00.000Z","description":"计算机三级嵌入式背题.","articleGPT":"计算机三级嵌入式背题.","head":[["link",{"rel":"canonical","href":"https://rinyuki.com/posts/2026/0325"}]]},"headers":[],"relativePath":"posts/2026/0325.md","filePath":"posts/2026/0325.md","lastUpdated":null}');const g=t({name:"posts/2026/0325.md"},[["render",function(t,n,g,i,l,e){return o(),r("div",null,n[0]||(n[0]=[s('<h1 id="计算机三级嵌入式背题" tabindex="-1">计算机三级嵌入式背题 <a class="header-anchor" href="#计算机三级嵌入式背题" aria-label="Permalink to &quot;计算机三级嵌入式背题&quot;">​</a></h1><ul><li>为提高SoC的设计效率，减少重复开发，通常大多以IP核为基础，在单个芯片上集成处理器，存储器和各种接口等组件，组成一个相当完整的计算机系统。按照IC设计文件的类型，IP核通常分为三种：<strong>软</strong>核、固核和<strong>硬</strong>核。</li><li>目前数码相机中用于存储所拍摄相片的大多是<strong>Dlash</strong>存储器，假设一台数码相机一次可连续拍摄65536色的1024*1024的彩色相片80张，数据压缩比平均是4，则它使用的存储器容量大约是<strong>40</strong>MB.</li><li>无线局域网（WLAN）是以太网与无线通信技术相结合的产物。它借助无线电波进行数据传输，所采用的通信协议主要是IEEE802.11，数据传输速率可以达到11Mbps,54Mbps,<strong>108</strong>Mbps甚至更高。</li><li>在 RISC-V 指令集架构中，主要包括复位 RESET、未定义指令 UND、软件中断 SWI、指令预取中止 PABT、数据访问中止 DABT、外部中断请求 IRQ 以及<strong>快速中断FIQ</strong>，其中优先级最高的异常是<strong>复位RESET</strong>。</li><li>ARM处理器Cortex系列包括Cortex嵌入式处理器和Cortex应用处理器，其中Cortex嵌入式处理器包括主要应用于控制领域的<strong>Cortex-M</strong>系列和面向实时应用领域的<strong>Cortex-R</strong>系列。</li><li>Thumb-2指令集提供了专门用于开、关中断的专用指令，关外部中断使用的指令为：<strong>CPSID I</strong>，开外部中断的指令为：<strong>CPSIE I</strong>。</li><li>已知ARM处理器R1=0x12345678，R2=0xFF008899，则执行指令AND R0,R1,R2后，寄存器R0=<strong>0x12000018</strong>，R1=<strong>0x12345678</strong>。</li><li>某ARM汇编语言程序要调用子程序，子程序名为MySubrutine，则调用该子程序的指令为<strong>BL MySubrutine</strong>，子程序返回调用程序的指令为<strong>MOV PC,LR</strong>。</li><li>按照AMBA总线规范，基于ARM内核的嵌入式处理器芯片采用系统总线与<strong>外围</strong>总线两层结构的方式构建片上系统。其中的系统总线主要用于连接<strong>高</strong>带宽快速组件。</li><li>嵌入式系统的存储器以半导体存储器为主。随着技术的不断发展，新型存储器不断出现，主要包括FRAM和MRAM，分别称为<strong>铁电</strong>存储器和<strong>磁性</strong>存储器。</li><li>半导体存储器芯片的存储容量取决于该芯片的<strong>地址</strong>总线的条数和<strong>数据</strong>总线的位数。</li><li>I²C总线被启动后，多个主机在每发送一个数据位时都要对SDA信号线电平进行检测，只要检测的电平与自己发出的电平<strong>相同</strong>就会继续占用总线。总线控制遵循的原则是谁先发送<strong>低</strong>电平谁就会掌握对总线的控制权。</li><li>UART由<strong>发送</strong>器，<strong>接收</strong>器，控制单元及波特率发生器等构成。</li><li>嵌入式系统与通用计算机系统软件的相同之处，指的是嵌入式系统通常也具备<strong>引导</strong>加载程序，外设<strong>驱动</strong>程序，操作系统，文件系统，网络协议栈，图形用户界面，数据库，以及各种各样的应用程序等，这些软件都是通用计算机所拥有的。</li><li>数据库管理系统、图形用户界面、互联网浏览器、媒体播放器等软件，如果运行在嵌入式系统上，往往具有内部结构精简、<strong>代码</strong>轻量化，占用存储资源<strong>少</strong>的特点。</li><li>实时系统的主要特征是能够及时响应外部发生的随机任务请求并且能够在规定的时限内完成任务。任务时限有两种：<strong>截止</strong>时间，也就是任务开始执行时间到任务必须完成的时间间隔。<strong>任务执行预设</strong>时间，或者叫做任务最早完成时间，这是无中断响应情况下的任务最早执行时间。</li><li>实时系统对时间约束要求的严格性，使<strong>可预测</strong>性成为实时系统的一项重要性能要求，它是指RTOS能够对外部事件的<strong>响应</strong>时间和实时任务的执行时间进行判断，以确定被事件触发的实时任务能否在规定的时间内完成。</li><li>一般按响应时间将实时系统分成三类：<strong>强</strong>实时系统，其响应时间一般在毫秒级或微秒级；普通实时系统，其响应时间一般在秒级；<strong>弱</strong>实时系统，其响应时间一般在数十秒级。</li></ul>',2)]))}]]);export{n as __pageData,g as default};
